var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"사장님께는 이 회사에 온 뒤부터 줄곧 관심을 갖고 있었어요.","JPN":"あなたのことは、この会社に来てからずっと興味を持っていましたわ。","ENG":"I've been watching you since they day I came here. ","TWN":"自從來到這個公司，我就對老闆非常感興趣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"저 역시, 한 조직을 관리하는 입장이니까요.","JPN":"私も一つの組織を管理する立場ですので。","ENG":"As someone who's in the position of leading an organization,","TWN":"畢竟我也站在管理一個組織的立場嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그리 번듯한 조직은 아니지만, 제멋대로인 사원들을 훌륭하게 이끄시는 모습이 무척 인상","JPN":"そんなに立派な組織じゃありませんが、わがままな社員たちをちゃんと率いる姿がとても印象に","ENG":"the leadership you exhibited while running this small business was ","TWN":"雖然不是什麼一流組織，但您完美地領導那些任性員工的身姿，給我留下了非常"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"깊혔......?!","JPN":"ぶきゃっ……！？","ENG":"quite impre— Ow, ow!","TWN":"深刻……？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"으윽...... 혀 깨물었어......","JPN":"ううっ……舌、噛んだ……","ENG":"Hngh... I bit my tongue... It hurts...","TWN":"嗚嗚……咬到舌頭了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"크흠, 흠! 무척 인상 깊었어요! 그러니까......!","JPN":"こほん、ふん！とても印象深かったですわ！ですから……！","ENG":"Ahem! What I'm trying to tell you is... Erm...","TWN":"咳咳！非常深刻的印象！所以……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"......잠깐, 원래 그렇게 안색이 창백하셨던가요?","JPN":"……ちょっと、元々そんなに顔色が青白かったでしょうか？","ENG":"Wait, were you always that pale?","TWN":"……等等，您的臉色怎麼這麼蒼白？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"죄, 죄송해요! 긴장하는 바람에 저도 모르게 냉기를 풀풀 날리고 있었네요! 어서 온풍기를 틀죠!","JPN":"す、すみません！緊張のあまり、知らないうちに冷気を放っていましたわ！早く暖房をつけましょう！","ENG":"Oh, s-sorry! I was so nervous that I didn't even notice I was freezing up the air here. Let's turn the heater on, shall we?","TWN":"非、非常抱歉！我太緊張了，不知不覺就放出了寒氣！快點把暖氣打開！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"망했어...... 이런 중요한 자리에서 실수를 저지르다니......","JPN":"しまった……こんな大事な時にミスをするなんて……","ENG":"I'm so stupid... How can I make such a big mistake in a situation like this?","TWN":"真糟糕……居然在這麼重要的場合失誤……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"전 역시 갈 길이 머네요. 팬드래건 양처럼 되기엔 아직 배워야 할 것들이 많아요.","JPN":"私はまだまだです。ペンドラゴンさんみたいになるためにはいろいろ学ばないといけませんわね。","ENG":"I guess I still have a long way to go. I still have lots to learn to be like Ms. Pendragon.","TWN":"我要走的路還很長呢。要成為潘德拉貢小姐那樣的人，我還有很多東西要學。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"하지만......","JPN":"ですが……","ENG":"And...","TWN":"但是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"역시, 기왕 배워야 한다면 사장님께 배우고 싶어요.","JPN":"やっぱり、学ぶとしたら社長に学びたいですわ。","ENG":"if I need to learn, I want to learn from you.","TWN":"既然都要學，那我想要向老闆學習。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그런 의미에서 여쭤 보는 건데...... 혹시 손난로 가지고 계시면 좀 빌릴 수 있을까요?","JPN":"というわけでお聞きしますが……もしカイロを持っていらっしゃるなら貸していただけますか？","ENG":"And on that note, I'd like to ask you a question. Do you have a spare handwarmer that I can borrow?","TWN":"所以想請問一下……不知道您有沒有暖暖包能借我一下？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};